pub fn agent_registered_topic() -> B256 { keccak256("AgentRegistered(address,address,address,uint64)") }
pub fn heartbeat_topic() -> B256 { keccak256("Heartbeat(address,uint64,string,address)") }
pub fn agent_failed_topic() -> B256 { keccak256("AgentFailed(address,uint64,uint64)") }
pub fn agent_removed_topic() -> B256 { keccak256("AgentRemoved(address,string)") }
pub fn revival_initiated_topic() -> B256 { keccak256("RevivalInitiated(address,string,address,uint64)") }
pub fn agent_revived_topic() -> B256 { keccak256("AgentRevived(address,string)") }

pub fn decode_address_from_topic(topic: &B256) -> Address {
    Address::from_slice(&topic.as_slice()[12..])
}

pub fn decode_uint64_from_bytes(data: &[u8], offset: usize) -> u64 {
    if data.len() < offset + 32 { return 0; }
    let mut bytes = [0u8; 8];
    bytes.copy_from_slice(&data[offset + 24..offset + 32]);
    u64::from_be_bytes(bytes)
}
